do $$ begin create role anon; exception when duplicate_object then null; end $$;
do $$ begin create role authenticated; exception when duplicate_object then null; end $$;
do $$ begin create role service_role; exception when duplicate_object then null; end $$;
create schema if not exists auth;
create or replace function auth.uid() returns uuid language sql stable as $fn$ select nullif(current_setting('request.jwt.claim.sub', true), '')::uuid $fn$;
create schema if not exists storage;
create table if not exists storage.buckets (id text primary key, name text, public boolean default false);
create table if not exists storage.objects (id uuid default gen_random_uuid() primary key, bucket_id text, name text, owner uuid, created_at timestamptz default now());
alter table storage.objects enable row level security;
create or replace function public.trigger_notify_nieuwe_lead() returns trigger language plpgsql as $fn$ begin return new; end $fn$;
create or replace function public.trigger_notify_lead_update() returns trigger language plpgsql as $fn$ begin return new; end $fn$;
create or replace function public.trigger_notification_dispatch() returns trigger language plpgsql as $fn$ begin return new; end $fn$;
create or replace function public.dispatch_notification_delivery(p_id uuid, p_kanaal public.notification_kanaal) returns void language plpgsql as $fn$ begin end $fn$;
create or replace function public.create_notification_for_all_users(p_event_type public.notification_event_type, p_titel text, p_body text, p_lead_id text, p_payload jsonb) returns void language plpgsql as $fn$ begin end $fn$;
create or replace function public.next_offerte_nummer() returns text language sql as $fn$ select '0'::text $fn$;
create or replace function public.is_approved_dashboard_user() returns boolean language sql stable as $fn$ select true $fn$;
